   137→func bpfMasqAddrs(ifName string, cfg *datapath.LocalNodeConfiguration) (masq4, masq6 netip.Addr) {
   138→	if cfg.DeriveMasqIPAddrFromDevice != "" {
   139→		ifName = cfg.DeriveMasqIPAddrFromDevice
   140→	}
   141→
   142→	find := func(devName string) bool {
   143→		for _, addr := range cfg.NodeAddresses {
   144→			if addr.DeviceName != devName {
   145→				continue
   146→			}
   147→			if !addr.Primary {
   148→				continue
   149→			}
   150→			if addr.Addr.Is4() && !masq4.IsValid() {
   151→				masq4 = addr.Addr
   152→			} else if addr.Addr.Is6() && !masq6.IsValid() {
   153→				masq6 = addr.Addr
   154→			}
   155→			done := (!option.Config.EnableIPv4Masquerade || masq4.IsValid()) &&
   156→				(!option.Config.EnableIPv6Masquerade || masq6.IsValid())
   157→			if done {
   158→				return true
   159→			}
   160→		}
   161→		return false
   162→	}
   163→
   164→	// Try to find suitable masquerade address first from the given interface.
   165→	if !find(ifName) {
   166→		// No suitable masquerade addresses were found for this device. Try the fallback
   167→		// addresses.
   168→		find(tables.WildcardDeviceName)
   169→	}
   170→
   171→	return
   172→}
