    22→// EndpointRegenerationEvent contains all fields necessary to regenerate an endpoint.
    23→type EndpointRegenerationEvent struct {
    24→	regenContext *regenerationContext
    25→	ep           *Endpoint
    26→}
    27→
    28→// Handle handles the regeneration event for the endpoint.
    29→func (ev *EndpointRegenerationEvent) Handle(res chan interface{}) {
    30→	e := ev.ep
    31→	regenContext := ev.regenContext
    32→
    33→	// Compute policy on the first regeneration before acquiring the build permit in
    34→	// QueueEndpointBuild below
    35→	select {
    36→	case <-e.initialEnvoyPolicyComputed:
    37→		// Already done
    38→	default:
    39→		err, release := e.ComputeInitialPolicy(regenContext)
    40→		if err != nil {
    41→			if !errors.Is(err, context.Canceled) {
    42→				e.getLogger().WithError(err).Error("Initial policy compute failed")
    43→			}
    44→
    45→			res <- &EndpointRegenerationResult{
    46→				err: err,
    47→			}
    48→			return
    49→		}
    50→		// release policy results when done
    51→		defer release()
    52→	}
    53→
    54→	err := e.rlockAlive()
    55→	if err != nil {
    56→		e.logDisconnectedMutexAction(err, "before regeneration")
    57→		res <- &EndpointRegenerationResult{
    58→			err: err,
    59→		}
    60→		return
    61→	}
    62→	e.runlock()
    63→
    64→	// We should only queue the request after we use all the endpoint's
    65→	// lock/unlock. Otherwise this can get a deadlock if the endpoint is
    66→	// being deleted at the same time. More info PR-1777.
    67→	doneFunc, err := e.owner.QueueEndpointBuild(regenContext.parentContext, uint64(e.ID))
    68→	if err != nil {
    69→		if !errors.Is(err, context.Canceled) {
    70→			e.getLogger().WithError(err).Warning("unable to queue endpoint build")
    71→		}
    72→	} else if doneFunc != nil {
    73→		e.getLogger().Debug("Dequeued endpoint from build queue")
    74→
    75→		regenContext.DoneFunc = doneFunc
    76→
    77→		err = ev.ep.regenerate(ev.regenContext)
    78→
    79→		doneFunc()
    80→		e.notifyEndpointRegeneration(err)
    81→	} else {
    82→		// If another build has been queued for the endpoint, that means that
    83→		// that build will be able to take care of all of the work needed to
    84→		// regenerate the endpoint at this current point in time; queueing
    85→		// another build is a waste of resources.
    86→		e.getLogger().Debug("build not queued for endpoint because another build has already been queued")
    87→	}
    88→
    89→	res <- &EndpointRegenerationResult{
    90→		err: err,
    91→	}
    92→}
