    99→// EndpointRevisionBumpEvent contains all fields necessary to bump the policy
   100→// revision of a given endpoint.
   101→type EndpointRevisionBumpEvent struct {
   102→	Rev uint64
   103→	ep  *Endpoint
   104→}
   105→
   106→// Handle handles the revision bump event for the Endpoint.
   107→func (ev *EndpointRevisionBumpEvent) Handle(res chan interface{}) {
   108→	// TODO: if the endpoint is not in a 'ready' state that means that
   109→	// we cannot set the policy revision, as something else has
   110→	// changed endpoint state which necessitates regeneration,
   111→	// *or* the endpoint is in a not-ready state (i.e., a prior
   112→	// regeneration failed, so there is no way that we can
   113→	// realize the policy revision yet. Should this be signaled
   114→	// to the routine waiting for the result of this event?
   115→	ev.ep.SetPolicyRevision(ev.Rev)
   116→	res <- struct{}{}
   117→}
   118→
   119→// PolicyRevisionBumpEvent queues an event for the given endpoint to set its
   120→// realized policy revision to rev. This may block depending on if events have
   121→// been queued up for the given endpoint. It blocks until the event has
   122→// succeeded, or if the event has been cancelled.
   123→func (e *Endpoint) PolicyRevisionBumpEvent(rev uint64) {
   124→	epBumpEvent := eventqueue.NewEvent(&EndpointRevisionBumpEvent{Rev: rev, ep: e})
   125→	// Don't check policy revision event results - it is best effort.
   126→	_, err := e.eventQueue.Enqueue(epBumpEvent)
   127→	if err != nil {
   128→		log.WithFields(logrus.Fields{
   129→			logfields.PolicyRevision: rev,
   130→			logfields.EndpointID:     e.ID,
   131→		}).Errorf("enqueue of EndpointRevisionBumpEvent failed: %s", err)
   132→	}
   133→}
